B.HP=A.a(s(["El enc\xe9falo y los nervios craneales.","La m\xe9dula espinal y los nervios espinales.","El enc\xe9falo y la m\xe9dula espinal.","El sistema nervioso som\xe1tico y el aut\xf3nomo."]),t.s)
