B.N_=A.a(s(["La planificaci\xf3n del movimiento.","La regulaci\xf3n de la respiraci\xf3n y el ritmo card\xedaco.","La memoria a largo plazo.","La comprensi\xf3n del lenguaje."]),t.s)
