B.Jf=A.a(s(["La capacidad de responder a est\xedmulos externos.","El mantenimiento de un ambiente interno relativamente constante.","El proceso de divisi\xf3n celular.","La transmisi\xf3n de impulsos nerviosos."]),t.s)
